func toggleReschedule(taskID string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_toggleReschedule_d6b9`,
		Function: `function __templ_toggleReschedule_d6b9(taskID){event.stopPropagation();
	const el = document.getElementById('resched-' + taskID);
	if (!el) return;
	if (el.classList.contains('hidden')) {
		// Close any other open reschedule panels
		document.querySelectorAll('[id^="resched-"]').forEach(function(other) {
			if (other !== el) {
				other.classList.add('hidden');
				other.classList.remove('flex');
			}
		});
		el.classList.remove('hidden');
		el.classList.add('flex');
	} else {
		el.classList.add('hidden');
		el.classList.remove('flex');
	}
}`,
		Call:       templ.SafeScript(`__templ_toggleReschedule_d6b9`, taskID),
		CallInline: templ.SafeScriptInline(`__templ_toggleReschedule_d6b9`, taskID),
	}
}

func formatDue(due string) string {
	t, err := time.Parse("2006-01-02", due)
	if err != nil {
		return due
	}
	now := time.Now()
	if t.Year() == now.Year() {
		return t.Format("Jan 2")
	}
	return t.Format("Jan 2, 2006")
}

func dueDateClass(due string, completed bool) string {
	if completed {
		return "text-gray-400 dark:text-gray-500"
	}
	t, err := time.Parse("2006-01-02", due)
	if err != nil {
		return "text-gray-400 dark:text-gray-500"
	}
	today := time.Now().Format("2006-01-02")
	todayT, _ := time.Parse("2006-01-02", today)
	if t.Before(todayT) {
		return "text-red-500 dark:text-red-400"
	}
	if t.Equal(todayT) {
		return "text-amber-500 dark:text-amber-400"
	}
	return "text-gray-400 dark:text-gray-500"
}

func dueDateBadgeClass(due string, completed bool) string {
	if completed {
		return "bg-gray-100 text-gray-400 dark:bg-gray-800 dark:text-gray-500"
	}
	t, err := time.Parse("2006-01-02", due)
	if err != nil {
		return "bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400"
	}
	today := time.Now().Format("2006-01-02")
	todayT, _ := time.Parse("2006-01-02", today)
	if t.Before(todayT) {
		return "bg-red-50 text-red-600 dark:bg-red-900/20 dark:text-red-400"
	}
	if t.Equal(todayT) {
		return "bg-amber-50 text-amber-600 dark:bg-amber-900/20 dark:text-amber-400"
	}
	return "bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400"
}

